sql:
SELECT m.*, ml.*
FROM messages m
JOIN message_logs ml ON m.id = ml.message_id;

SELECT subject
FROM messages
WHERE status = 'accepted';

SELECT COUNT(*) AS total_messages
FROM messages
WHERE status = 'accepted';

SELECT id
FROM messages
WHERE created_at = (SELECT MIN(created_at) FROM messages);

SELECT COUNT(*) AS unread_message_count
FROM messages
WHERE sender_id = 1 AND recipient_id = 2 AND is_read = 0;

external_knowledge:
'active users' refers to users who have sent more than 10 messages;
'a bunch of messages' refers to more than 10 messages sent;
'a good amount of messages' refers to more than 5 messages read.

